        pid = ++_propsCreated;  // See UINT_ROLLOVER
        Prop storage prop = _proposals[pid];
        prop.pid = pid;
        prop.creator = caller;
        prop.createdAt = block.timestamp;
        prop.expiredAt = expiredAt;
        prop.eid = reqId;
